#include <stdio.h>
#include <math.h>
#define MAXN 100005
#define MAXT 10
int T, n;
long long x[MAXN], y[MAXN], w[MAXN];
long long dist[MAXN][MAXN];
long double dp[MAXN][1 << 17];
int main() {
    scanf("%d", &T);
    while (T--) {
        scanf("%d", &n);
        for (int i = 0; i < n; i++) {
            scanf("%lld %lld", &x[i], &y[i]);
        }
        for (int i = 0; i < n; i++) {
            scanf("%lld", &w[i]);
        }
        for (int i = 0; i < n; i++) {
            for (int j = 0; j < n; j++) {
                dist[i][j] = (x[i] - x[j]) * (x[i] - x[j]) + (y[i] - y[j]) * (y[i] - y[j]);
            }
        }
        for (int i = 0; i < n; i++) {
            for (int j = 0; j < (1 << n); j++) {
                dp[i][j] = -1;
            }
        }
        long double ans = 0;
        for (int i = 0; i < n; i++) {
            ans = fmax(ans, dfs(0, (1 << i), 0));
        }
        printf("%.9Lf\n", ans);
    }
    return 0;
}
long double dfs(int u, int mask, long long sum) {
    if (dp[u][mask] != -1) return dp[u][mask];
    long double ret = 0;
    for (int i = 0; i < n; i++) {
        if ((mask & (1 << i)) == 0) continue;
        if (i == u) continue;
        long double tmp = dfs(i, mask ^ (1 << u), sum + w[u]);
        ret = fmax(ret, tmp + sqrt(dist[u][i]));
    }
    ret /= (sum + w[u]);
    dp[u][mask] = ret;
    return ret;
}

