                }
            }
            for (int i = 0; i < n; i++) {
                for (int j = 0; j < (1 << n); j++) {
                    dp[i][j] = -1;
                }
            }
            double ans = 0;
            for (int i = 0; i < n; i++) {
                ans = Math.max(ans, dfs(0, (1 << i), 0));
            }
            System.out.printf("%.9f\n", ans);
        }
    }
